script:
user = frappe.session.user

roles = frappe.db.get_all(
    "Has Role",
    filters={"parent": user},
    pluck="role"
)

if "Assistant Director" in roles and "Psc officer" in roles:
    doc.ad_is_psc = 1
else:
    doc.ad_is_psc = 0

if doc.reference_type == "Soil Sample Collection" and doc.reference_name:

    # When Assigned
    if doc.status == "Open":
        frappe.db.set_value(
            "Soil Sample Collection",
            doc.reference_name,
            "status",
            "With Research Assistant"
        )

if doc.reference_type == "Soil Sample Collection" and doc.reference_name:

    if doc.status == "Closed":
        frappe.db.set_value(
            "Soil Sample Collection",
            doc.reference_name,
            "status",
            "completed"
        )

    elif doc.status == "Cancelled":
        frappe.db.set_value(
            "Soil Sample Collection",
            doc.reference_name,
            "status",
            "Returned to Senior Chemist(Overload)"
        )

if doc.soil_sample_id:
    already_used = frappe.db.get_value(
        "Soil Sample Collection",
        doc.soil_sample_id,
        "lab_register_created"
    )

    if already_used:
        frappe.throw(
            f"Sample {doc.soil_sample_id} is already added to Register"
        )

schemes = set()

for row in doc.bulk_test_entry_item:
    scheme = frappe.db.get_value(
        "Soil Sample Collection",
        row.register_id,
        "scheme_name"
    )
    schemes.add(scheme)

if len(schemes) > 1:
    frappe.throw("All samples must belong to the same Scheme")

if doc.bulk_test_entry_item:

    for row in doc.bulk_test_entry_item:
        if not row.register_id:
            frappe.throw("Register ID missing in one of the rows")

        reg = frappe.get_doc("Register", row.register_id)

        if reg.client_type != "Department":
            frappe.throw(f"{row.register_id} is not a Department sample")

    schemes = set()

    for row in doc.bulk_test_entry_item:
        if row.register_id:
            scheme = frappe.get_value("Register", row.register_id, "scheme_name")
            if scheme:
                schemes.add(scheme)

    if len(schemes) > 1:
        frappe.throw("All samples must belong to the same Scheme")

# Server Script: Before Save

existing_values = {}

for v in doc.variable_inputs:
    key = (v.test_item, v.variable_key)
    existing_values[key] = v.value

new_rows = []

for test_row in doc.results_table:

    master = frappe.get_doc("Soil Test Package", test_row.test_item)

    if not master.variable_table:
        continue

    for m_var in master.variable_table:

        key = (test_row.test_item, m_var.variable_key)

        new_rows.append({
            "variable_key": m_var.variable_key,
            "description": m_var.label,
            "parent_test_row": test_row.name,
            "test_item": test_row.test_item,
            "value": existing_values.get(key, 0)
        })


# Only rebuild table if count changed
if len(doc.variable_inputs) != len(new_rows):

    doc.set("variable_inputs", [])

    for row in new_rows:
        doc.append("variable_inputs", row)
